parameters.jsCode:
const revenueData = $fromAI('revenueData', 'Revenue data for tax calculation', 'json');

try {
  const data = typeof revenueData === 'string' ? JSON.parse(revenueData) : revenueData;

  const revenue = parseFloat(data.revenueAmount || data.grossRevenue || 0);
  const region = data.region || 'US';

  // Tax rates by region
  const taxRates = {
    'US': 0.21,
    'EU': 0.25,
    'UK': 0.19,
    'APAC': 0.17
  };

  const taxRate = taxRates[region] || 0.21;
  const taxLiability = revenue * taxRate;
  const netRevenue = revenue - taxLiability;

  const result = {
    revenue: revenue.toFixed(2),
    region: region,
    taxRate: taxRate,
    taxLiability: taxLiability.toFixed(2),
    netRevenue: netRevenue.toFixed(2),
    calculationDate: new Date().toISOString()
  };

  return JSON.stringify(result, null, 2);

} catch (error) {
  return JSON.stringify({
    error: 'Tax calculation failed',
    message: error.message,
    taxLiability: 0
  });
}

